#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.skeletonStatue_Animation)]
    public class SkeletonStatue_AnimationBehaviour : HumanoidAnimationBehaviour
    {
        public SkeletonStatue_AnimationBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void ModifyAnimationParameters(Entity entity, int state, ref AnimationParameters parameters)
        {
            base.ModifyAnimationParameters(entity, state, ref parameters);
            if (state == STATE_REVIVING || state == STATE_DEATH)
            {
                parameters.walkState = WALK_STATE_NONE;
                parameters.armState = ARM_STATE_NONE;
                parameters.specialState = SPECIAL_STATE_REVIVING;
            }
        }
        public const int STATE_REVIVING = VanillaEnemyStates.SKELETON_STATUE_REVIVING;
        public const int SPECIAL_STATE_REVIVING = 1;
    }
}